CREATE INDEX "accounts_medal_ranking_idx" ON "scoresaber-accounts" USING btree ("medals" DESC NULLS LAST,"id" ASC NULLS LAST) WHERE "scoresaber-accounts"."medals" > 0 AND "scoresaber-accounts"."banned" = false AND "scoresaber-accounts"."country" IS NOT NULL AND "scoresaber-accounts"."country" <> '';--> statement-breakpoint
CREATE INDEX "accounts_medal_ranking_country_idx" ON "scoresaber-accounts" USING btree ("country","medals" DESC NULLS LAST,"id" ASC NULLS LAST) WHERE "scoresaber-accounts"."medals" > 0 AND "scoresaber-accounts"."banned" = false AND "scoresaber-accounts"."country" IS NOT NULL AND "scoresaber-accounts"."country" <> '';--> statement-breakpoint
CREATE INDEX "accounts_stale_medals_rank_idx" ON "scoresaber-accounts" USING btree ("id") WHERE "scoresaber-accounts"."medalsRank" <> 0 OR "scoresaber-accounts"."medalsCountryRank" <> 0;
